  ('pukao-6f0ba476-moex-00349', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '乙公司於X1年12月份以庫藏股票50,000股換入一筆土地，以作為新建廠房用地，該土地上有 一舊車庫，已知乙公司股票每股面額為$10，庫藏股票成本每股$140，交換當日公允價值每股$160， 拆除舊車庫與出售殘料共得淨價款$600,000，則土地的入帳成本為？', '["$6,400,000", "$7,000,000", "$7,400,000", "$8,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00350', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '若無其他資料，下列何者可協助財務報表使用者評估企業自有資金之占比？', '["淨利率", "負債比率", "股東權益報酬率", "應收帳款週轉率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00351', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年5月1日以每股$30購入庫藏股10,000股，於X1年底公司股價為每股$35，甲公 司於X2年6月30日以每股$36將庫藏股全數再發行。有關前述庫藏股交易之影響，下列敘述何 者正確？', '["X1年底權益將減少$250,000", "X1年度淨利將增加$50,000", "X2年度保留盈餘將增加$10,000", "X2年底權益將增加$360,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00352', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '乙公司於X6年7月初以$270,000購入一台機器，估計耐用年限5年，殘值$20,000，使用直線法 提列折舊與成本模式衡量。X7年底由於經營環境改變，使得該機器之價值有重大跡象顯示已經發 生減損。乙公司於X7年底作減損測試，估計該機器之使用價值為$175,000，公允價值減處分成本 為$165,000，估計耐用年限不變。乙公司X7年應認列之減損損失為？', '["$0", "$14,000", "$20,000", "$30,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00353', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '乙公司 X5 年相關資料如下：購買一台機器付款$75,000，根據關聯企業淨利所認列之投資收益 $55,000，簽發票據$110,000取得一筆土地，發行公司債$260,000。X5年度折舊費用$25,000。X5 年度應收帳款淨額減少$30,000，存貨淨額增加$20,000，應付帳款增加$30,000。X5 年度淨利 $80,000，期初現金餘額$48,000。乙公司X5年的營業活動淨現金流入為？', '["$15,000", "$30,000", "$90,000", "$145,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00354', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '有關公司債，下列敘述何者正確？', '["當公司債為折價發行時，債券的利息費用會逐期增加，折價攤銷數會逐期減少，公司債帳面金 額會逐期增加", "當公司債為溢價發行時，債券的利息費用會逐期降低，溢價攤銷數會逐期增加，公司債帳面金 額會逐期減少", "當公司債為折價發行時，債券的利息費用會逐期降低，折價攤銷數會逐期增加，公司債帳面金 額會逐期增加", "當公司債為溢價發行時，債券的利息費用會逐期增加，溢價攤銷數會逐期減少，公司債帳面金 額會逐期減少"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00355', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司採定期盤存制，於X1年12月30日收到一筆寄銷人寄銷的商品，甲公司將其列為進貨， 但並未列入期末存貨的盤存數中，該錯誤對於X1年度財務報表有何影響？', '["淨利正確，營運資金不受影響", "淨利低估，營運資金高估", "淨利低估，營運資金低估", "淨利正確，營運資金低估"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00356', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司X1年初平價發行公司債$1,000,000，票面利率10%。X1年底資產負債表顯示，資產總額 $2,500,000，流動負債$500,000，權益$1,000,000。X1年度綜合損益表顯示：本期淨利$520,000與 所得稅費用$30,000。請問X1年12月31日甲公司之利息保障倍數為？', '["6.50倍", "5.20倍", "4.80倍", "5.50倍 | 41530"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00357', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司於X1年初購入一部機器$1,200,000，估計耐用年限6年，無殘值，採直線法提列折舊。於 X3年底認列折舊前，甲公司估計該機器剩餘耐用年限4年，無殘值，但宜自X3年起改採年數合 計法更符合效益消耗型態。請問下列敘述何者正確？（答案四捨五入至元）', '["X3年度之折舊費用為$266,667", "X4年度之折舊費用為$240,000", "X3年底之累計折舊為$600,000", "X4年底之累計折舊為$942,857"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00358', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-d35177eb', 'sub-pukao-6f0ba476-01', NULL, 'single_choice', '甲公司在X1年初購入設備，該設備成本$60,000，預估耐用年限為5年，殘值$6,000，採年數合 計法提列折舊並採成本模式後續衡量。X3年初因該設備之運作方式改變，改採直線法提列折舊， 預估耐用年限與殘值均未改變。X3年底該設備之帳面金額應為多少？', '["$14,400", "$20,400", "$21,600", "$27,600"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
